sucursales_v,CREATE VIEW sucursales_v AS   SELECT s.*, l.cod_zona_geo  FROM sucursales_clientes s  LEFT JOIN localidades l ON s.cod_pais = l.cod_pais AND s.cod_provincia = l.cod_provincia AND s.cod_localidad_nro = l.cod_localidad_nro    
tareas_cabecera_v,CREATE VIEW tareas_cabecera_v AS   SELECT tc.*, o.cod_articulo, o.cod_color_articulo, o.version   FROM Tareas_cabecera tc   INNER JOIN Orden_fabricacion o ON o.nro_orden_fabricacion = tc.nro_orden_fabricacion  
tareas_detalle_v,  CREATE VIEW tareas_detalle_v AS   SELECT td.*, tc.anulado, o.cod_articulo, o.cod_color_articulo, o.version, c.vigente, a.vigente articulo_vigente, a.naturaleza   FROM Tareas_detalle td   INNER JOIN Tareas_cabecera tc ON tc.nro_orden_fabricacion = td.nro_
