usuarios_por_almacen_v,      --Es porque la clase UsuarioPorAlmacen hereda de Usuario y necesita todos sus campos para el fill    CREATE VIEW usuarios_por_almacen_v AS  SELECT a.cod_almacen, b.*  FROM usuarios_por_almacen a  INNER JOIN users b ON a.cod_usuario = b.cod_usuario
usuarios_por_area_empresa_v,  CREATE VIEW usuarios_por_area_empresa_v AS   SELECT a.id_area_empresa, b.*   FROM usuarios_por_area_empresa a   INNER JOIN users b ON a.cod_usuario = b.cod_usuario
usuarios_por_caja_v,      CREATE VIEW [dbo].[usuarios_por_caja_v] AS   SELECT  c.cod_caja, c.nombre, p.cod_usuario,      (CASE WHEN (SELECT count(*) FROM cuenta_bancaria cb WHERE cb.cod_caja = c.cod_caja) > 0 THEN 'S' ELSE 'N' END) es_caja_banco   FROM  usuarios_por_caja p IN
usuarios_por_seccion_v,  CREATE VIEW [dbo].[usuarios_por_seccion_v] AS  SELECT a.cod_seccion, b.*  FROM usuarios_por_seccion a  INNER JOIN users b ON a.cod_usuario = b.cod_usuario
usuarios_por_tipo_notificacion_v,  CREATE VIEW usuarios_por_tipo_notificacion_v AS    SELECT a.cod_tipo_notificacion, a.eliminable, b.*  FROM usuarios_por_tipo_notificacion a  INNER JOIN users b ON a.cod_usuario = b.cod_usuario
