VIEW1,CREATE VIEW dbo.VIEW1  AS  SELECT     situacion, cod_seccion, cod_articulo, denom_articulo, cod_color_articulo, SUM(cantidad) AS cant  FROM         dbo.tareas_incumplidas_v  GROUP BY situacion, cod_seccion, cod_articulo, denom_articulo, cod_color_articulo 
VIEW2,CREATE VIEW dbo.VIEW2  AS  SELECT     TOP 100 PERCENT empresa, 1 AS punto_venta, 'REC' AS tipo_docum, nro_recibo AS numero, 'R' AS letra, nro_recibo AS nro_comprobante,                         anulado, NULL AS tipo_docum_2, dbo.IfNullZero(cod_cliente) AS c
VIEW3,CREATE VIEW dbo.VIEW3  AS  SELECT     TOP 100 PERCENT dbo.colores_por_articulo.catalogo_orden_pagina AS [Position], 'Spiral' AS Manufacturer, '' AS Supplier,                         dbo.colores_por_articulo.cod_articulo + dbo.colores_por_articulo.cod_color
